const items = $input.all();
const umaSemanaAtras = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const semana = items.filter(i => new Date(i.json.data_entrada) >= umaSemanaAtras);
const hot = semana.filter(i => i.json.classificacao === 'HOT').length;
const warm = semana.filter(i => i.json.classificacao === 'WARM').length;
const cold = semana.filter(i => i.json.classificacao === 'COLD').length;
const fechados = semana.filter(i => i.json.status === 'FECHADO').length;
return [{ json: { total_leads: semana.length, hot, warm, cold, fechados, taxa_conversao: semana.length > 0 ? ((fechados/semana.length)*100).toFixed(1)+'%' : '0%', periodo: umaSemanaAtras.toLocaleDateString('pt-BR') + ' a ' + new Date().toLocaleDateString('pt-BR'), leads_raw: JSON.stringify(semana.slice(0,10).map(i => i.json)) } }];

const analysis = $input.first().json.content[0].text;
const metrics = $('Calcula Metricas').first().json;
const html = `<h2>Relatorio Semanal de Vendas - ${metrics.periodo}</h2><hr><h3>Metricas</h3><ul><li>Total de leads: ${metrics.total_leads}</li><li>HOT: ${metrics.hot} | WARM: ${metrics.warm} | COLD: ${metrics.cold}</li><li>Fechados: ${metrics.fechados} (${metrics.taxa_conversao})</li></ul><h3>Analise IA</h3><p>${analysis.replace(/\n/g, '<br>')}</p>`;
return [{ json: { html_report: html, analysis, ...metrics } }];
